class ProjectComponent(BaseModel):
    """
    Details about a project component.
    """

    model_config = ConfigDict(
        extra='forbid',
    )
    assignee: User | None = None
    """
    The details of the user associated with `assigneeType`, if any. See `realAssignee` for details of the user assigned to issues created with this component.
    """
    assignee_type: AssigneeType3 | None = Field(default=None, alias='assigneeType')
    """
    The nominal user type used to determine the assignee for issues created with this component. See `realAssigneeType` for details on how the type of the user, and hence the user, assigned to issues is determined. Can take the following values:

     *  `PROJECT_LEAD` the assignee to any issues created with this component is nominally the lead for the project the component is in.
     *  `COMPONENT_LEAD` the assignee to any issues created with this component is nominally the lead for the component.
     *  `UNASSIGNED` an assignee is not set for issues created with this component.
     *  `PROJECT_DEFAULT` the assignee to any issues created with this component is nominally the default assignee for the project that the component is in.

    Default value: `PROJECT_DEFAULT`.  
    Optional when creating or updating a component.
    """
    description: str | None = None
    """
    The description for the component. Optional when creating or updating a component.
    """
    id: str | None = None
    """
    The unique identifier for the component.
    """
    is_assignee_type_valid: bool | None = Field(
        default=None, alias='isAssigneeTypeValid'
    )
    """
    Whether a user is associated with `assigneeType`. For example, if the `assigneeType` is set to `COMPONENT_LEAD` but the component lead is not set, then `false` is returned.
    """
    lead: User | None = None
    """
    The user details for the component's lead user.
    """
    lead_account_id: str | None = Field(
        default=None, alias='leadAccountId', max_length=128
    )
    """
    The accountId of the component's lead user. The accountId uniquely identifies the user across all Atlassian products. For example, *5b10ac8d82e05b22cc7d4ef5*.
    """
    lead_user_name: str | None = Field(default=None, alias='leadUserName')
    """
    This property is no longer available and will be removed from the documentation soon. See the [deprecation notice](https://developer.atlassian.com/cloud/jira/platform/deprecation-notice-user-privacy-api-migration-guide/) for details.
    """
    name: str | None = None
    """
    The unique name for the component in the project. Required when creating a component. Optional when updating a component. The maximum length is 255 characters.
    """
    project: str | None = None
    """
    The key of the project the component is assigned to. Required when creating a component. Can't be updated.
    """
    project_id: int | None = Field(default=None, alias='projectId')
    """
    The ID of the project the component is assigned to.
    """
    real_assignee: User | None = Field(default=None, alias='realAssignee')
    """
    The user assigned to issues created with this component, when `assigneeType` does not identify a valid assignee.
    """
    real_assignee_type: RealAssigneeType | None = Field(
        default=None, alias='realAssigneeType'
    )
    """
    The type of the assignee that is assigned to issues created with this component, when an assignee cannot be set from the `assigneeType`. For example, `assigneeType` is set to `COMPONENT_LEAD` but no component lead is set. This property is set to one of the following values:

     *  `PROJECT_LEAD` when `assigneeType` is `PROJECT_LEAD` and the project lead has permission to be assigned issues in the project that the component is in.
     *  `COMPONENT_LEAD` when `assignee`Type is `COMPONENT_LEAD` and the component lead has permission to be assigned issues in the project that the component is in.
     *  `UNASSIGNED` when `assigneeType` is `UNASSIGNED` and Jira is configured to allow unassigned issues.
     *  `PROJECT_DEFAULT` when none of the preceding cases are true.
    """
    self: AnyUrl | None = None
    """
    The URL of the component.
    """


