class WorkflowScheme(BaseModel):
    """
    Details about a workflow scheme.
    """

    model_config = ConfigDict(
        extra='forbid',
    )
    default_workflow: str | None = Field(default=None, alias='defaultWorkflow')
    """
    The name of the default workflow for the workflow scheme. The default workflow has *All Unassigned Issue Types* assigned to it in Jira. If `defaultWorkflow` is not specified when creating a workflow scheme, it is set to *Jira Workflow (jira)*.
    """
    description: str | None = None
    """
    The description of the workflow scheme.
    """
    draft: bool | None = None
    """
    Whether the workflow scheme is a draft or not.
    """
    id: int | None = None
    """
    The ID of the workflow scheme.
    """
    issue_type_mappings: dict[str, str] | None = Field(
        default=None, alias='issueTypeMappings'
    )
    """
    The issue type to workflow mappings, where each mapping is an issue type ID and workflow name pair. Note that an issue type can only be mapped to one workflow in a workflow scheme.
    """
    issue_types: dict[str, IssueTypeDetails] | None = Field(
        default=None, alias='issueTypes'
    )
    """
    The issue types available in Jira.
    """
    last_modified: str | None = Field(default=None, alias='lastModified')
    """
    The date-time that the draft workflow scheme was last modified. A modification is a change to the issue type-project mappings only. This property does not apply to non-draft workflows.
    """
    last_modified_user: User | None = Field(default=None, alias='lastModifiedUser')
    """
    The user that last modified the draft workflow scheme. A modification is a change to the issue type-project mappings only. This property does not apply to non-draft workflows.
    """
    name: str | None = None
    """
    The name of the workflow scheme. The name must be unique. The maximum length is 255 characters. Required when creating a workflow scheme.
    """
    original_default_workflow: str | None = Field(
        default=None, alias='originalDefaultWorkflow'
    )
    """
    For draft workflow schemes, this property is the name of the default workflow for the original workflow scheme. The default workflow has *All Unassigned Issue Types* assigned to it in Jira.
    """
    original_issue_type_mappings: dict[str, str] | None = Field(
        default=None, alias='originalIssueTypeMappings'
    )
    """
    For draft workflow schemes, this property is the issue type to workflow mappings for the original workflow scheme, where each mapping is an issue type ID and workflow name pair. Note that an issue type can only be mapped to one workflow in a workflow scheme.
    """
    self: AnyUrl | None = None
    update_draft_if_needed: bool | None = Field(
        default=None, alias='updateDraftIfNeeded'
    )
    """
    Whether to create or update a draft workflow scheme when updating an active workflow scheme. An active workflow scheme is a workflow scheme that is used by at least one project. The following examples show how this property works:

     *  Update an active workflow scheme with `updateDraftIfNeeded` set to `true`: If a draft workflow scheme exists, it is updated. Otherwise, a draft workflow scheme is created.
     *  Update an active workflow scheme with `updateDraftIfNeeded` set to `false`: An error is returned, as active workflow schemes cannot be updated.
     *  Update an inactive workflow scheme with `updateDraftIfNeeded` set to `true`: The workflow scheme is updated, as inactive workflow schemes do not require drafts to update.

    Defaults to `false`.
    """


